// ─── Watercolor Engine ────────────────────────────────────────────────────────
function rng(seed, n) { const x = Math.sin(seed*9133+n*311)*43758.5453; return x-Math.floor(x); }
function wob(seed, i, amp) { return (rng(seed,i)-0.5)*amp; }

function smoothPath(pts, tension=0.55) {
  const n = pts.length;
  let d = `M ${pts[0][0].toFixed(1)} ${pts[0][1].toFixed(1)} `;
  for(let i=0;i<n;i++) {
    const p0=pts[(i-1+n)%n], p1=pts[i], p2=pts[(i+1)%n], p3=pts[(i+2)%n];
    const c1x=p1[0]+(p2[0]-p0[0])*tension/3, c1y=p1[1]+(p2[1]-p0[1])*tension/3;
    const c2x=p2[0]-(p3[0]-p1[0])*tension/3, c2y=p2[1]-(p3[1]-p1[1])*tension/3;
    d+=`C ${c1x.toFixed(1)} ${c1y.toFixed(1)},${c2x.toFixed(1)} ${c2y.toFixed(1)},${p2[0].toFixed(1)} ${p2[1].toFixed(1)} `;
  }
  return d+"Z";
}

function WCBlob({ color="sky", size=180, seed=1, opacity=0.85, rotate=0 }) {
  const id = useId();
  const c = T.wc[color]||T.wc.sky;
  const pts = [];
  for(let i=0;i<12;i++) {
    const a=(i/12)*Math.PI*2+wob(seed,i+1,0.18);
    const r=72+wob(seed,i,22);
    pts.push([100+Math.cos(a)*r, 100+Math.sin(a)*r]);
  }
  const d = smoothPath(pts);
  return (
    <svg viewBox="-10 -10 220 220" width={size} height={size}
      style={{transform:`rotate(${rotate}deg)`, overflow:"visible"}} aria-hidden="true">
      <defs>
        <radialGradient id={`wg-${id}`} cx="42%" cy="40%" r="70%">
          <stop offset="0%" stopColor={c.light} stopOpacity="0.95"/>
          <stop offset="40%" stopColor={c.base} stopOpacity="0.80"/>
          <stop offset="82%" stopColor={c.base} stopOpacity="0.55"/>
          <stop offset="100%" stopColor={c.deep} stopOpacity="0.18"/>
        </radialGradient>
        <radialGradient id={`we-${id}`} cx="50%" cy="50%" r="55%">
          <stop offset="60%" stopColor={c.deep} stopOpacity="0"/>
          <stop offset="92%" stopColor={c.deep} stopOpacity="0.35"/>
          <stop offset="100%" stopColor={c.deep} stopOpacity="0"/>
        </radialGradient>
        <filter id={`wf-${id}`} x="-20%" y="-20%" width="140%" height="140%">
          <feGaussianBlur stdDeviation="1.2"/>
        </filter>
        <clipPath id={`wc-${id}`}><path d={d}/></clipPath>
      </defs>
      <path d={d} fill={`url(#wg-${id})`} opacity={opacity}/>
      <path d={d} fill={`url(#we-${id})`} opacity={opacity} filter={`url(#wf-${id})`}/>
      <ellipse cx={70+wob(seed,11,14)} cy={74+wob(seed,12,12)}
        rx={22+wob(seed,13,6)} ry={9+wob(seed,14,3)}
        fill="white" opacity="0.35"
        transform={`rotate(${wob(seed,15,60)},100,100)`}
        clipPath={`url(#wc-${id})`}/>
    </svg>
  );
}

function WCCluster({ palette=["sky","lilac"], size=360, seed=1 }) {
  const blobs = palette.map((col,i) => {
    const angle = (i/palette.length)*Math.PI*2 + wob(seed+i,1,1.2);
    const dist = size*0.22 + wob(seed+i,2,size*0.08);
    const blobSize = size*(0.48+wob(seed+i,3,0.14));
    return { col, x:Math.cos(angle)*dist, y:Math.sin(angle)*dist, blobSize, seed:seed+i*7 };
  });
  const cx = size/2, cy = size/2;
  return (
    <svg viewBox={`0 0 ${size} ${size}`} width={size} height={size} overflow="visible" aria-hidden="true">
      {blobs.map((b,i) => (
        <foreignObject key={i} x={cx+b.x-b.blobSize/2} y={cy+b.y-b.blobSize/2}
          width={b.blobSize} height={b.blobSize} overflow="visible">
          <div xmlns="http://www.w3.org/1999/xhtml">
            <WCBlob color={b.col} size={b.blobSize} seed={b.seed} opacity={0.78-i*0.06}/>
          </div>
        </foreignObject>
      ))}
    </svg>
  );
}

function Sparkle({ size=60 }) {
  return (
    <svg viewBox="0 0 60 60" width={size} height={size} aria-hidden="true">
      <defs>
        <radialGradient id="spkg">
          <stop offset="0%" stopColor="#FCE39E"/><stop offset="100%" stopColor="#D6A974"/>
        </radialGradient>
      </defs>
      {[0,45,90,135].map(a => (
        <g key={a} transform={`rotate(${a},30,30)`}>
          <path d="M30 5 C31 20,30 20,30 30 C30 20,29 20,30 5Z" fill="url(#spkg)" opacity="0.9"/>
        </g>
      ))}
      <circle cx="30" cy="30" r="3.5" fill="#FCE39E" opacity="0.8"/>
      {[22.5,67.5,112.5,157.5].map(a => (
        <g key={a} transform={`rotate(${a},30,30)`}>
          <path d="M30 14 C30.6 22,30 22,30 30 C30 22,29.4 22,30 14Z" fill="url(#spkg)" opacity="0.55"/>
        </g>
      ))}
    </svg>
  );
}

function Feather({ size=110 }) {
  return (
    <svg viewBox="0 0 100 200" width={size*0.55} height={size} aria-hidden="true">
      <defs>
        <linearGradient id="fthg" x1="50%" y1="0%" x2="50%" y2="100%">
          <stop offset="0%" stopColor="#D8E6F0"/>
          <stop offset="60%" stopColor="#B0CFE0"/>
          <stop offset="100%" stopColor="#7EA0BB"/>
        </linearGradient>
      </defs>
      <path d="M50 10 Q50 100 50 195" stroke="#7EA0BB" strokeWidth="1.2" fill="none"/>
      <path d="M50 16 Q22 60 28 120 Q40 165 50 185 Q60 165 72 120 Q78 60 50 16Z" fill="url(#fthg)" opacity="0.85"/>
      <g stroke="#7EA0BB" strokeWidth="0.7" opacity="0.45">
        {Array.from({length:14}).map((_,i) => {
          const y=30+i*11, w=22-Math.abs(i-7)*2;
          return <line key={i} x1={50-w} y1={y+3} x2={50+w} y2={y-3}/>;
        })}
      </g>
    </svg>
  );
}

